package queries

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
	"github.com/jackc/pgx/v5/pgtype"
)

const pageSize = 200

type GetCoursesQuery interface {
	GetCourses(ctx context.Context, arg db.GetCoursesParams) ([]db.GetCoursesRow, error)
}

type Handlers struct {
	query GetCoursesQuery
}

type GetCoursesResult struct {
	Courses []db.GetCoursesRow `json:"courses"`
	Cursor  *string            `json:"cursor"`
}

func NewCoursesHandlers(qs GetCoursesQuery) *Handlers {
	return &Handlers{query: qs}
}

func parseGetCoursesQuery(r *http.Request) (keyword string, cursorUuid pgtype.UUID, err error) {
	keyword = r.URL.Query().Get("keyword")
	cursor := r.URL.Query().Get("cursor")

	if len([]rune(keyword)) > 40 {
		return "", pgtype.UUID{}, fmt.Errorf("keyword must be 40 characters or less")
	}
	if cursor != "" {
		if err := cursorUuid.Scan(cursor); err != nil {
			return "", pgtype.UUID{}, fmt.Errorf("invalid cursor")
		}
	}

	return keyword, cursorUuid, nil
}

func (handler *Handlers) GetCoursesHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	keyword, cursorUuid, err := parseGetCoursesQuery(r)
	if err != nil {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": response.InputValidationError, "message": err.Error()})
		return
	}

	rawCourses, err := handler.query.GetCourses(r.Context(), db.GetCoursesParams{Cursor: cursorUuid, Keyword: keyword, Size: pageSize + 1})
	if err != nil {
		log.Printf("GetCourses error: %v", err)
		w.WriteHeader(http.StatusInternalServerError)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": "INTERNAL_SERVER_ERROR", "message": "internal server error"})
		return
	}

	courses := rawCourses[0:min(len(rawCourses), pageSize)]

	var nextCursor *string
	if len(rawCourses) > pageSize {
		s := rawCourses[pageSize-1].CourseId.String()
		nextCursor = &s
	}

	_ = json.NewEncoder(w).Encode(GetCoursesResult{Courses: courses, Cursor: nextCursor})
}

package apikeys

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"strconv"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
	"github.com/harusame0616/ijuku/apps/api/lib/txrunner"
)

type generateApiKey struct {
	usecase generateApiKeyUsecase
}

func NewGenerateApiKeyHandler(usecase generateApiKeyUsecase) generateApiKey {
	return generateApiKey{
		usecase: usecase,
	}
}

func (generateApiKey generateApiKey) GenerateApiKeyHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	// TODO 認証

	userID := r.PathValue("userID")
	if userID == "" {
		// パスで UserID がマッピングされているのでこのパスは通過しない前提
		// ここを通過する場合はパスのマッピングが間違っているなどの不具合の可能性
		response.WriteInternalServerErrorResponse(w)
		return
	}

	parsedUserID, err := uuid.Parse(userID)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "User ID must be valid UUID")
		return
	}

	var bodyParams struct {
		ExpiredAt *time.Time `json:"expiredAt"`
	}

	defer r.Body.Close()
	if err := json.NewDecoder(r.Body).Decode(&bodyParams); err != nil {
		var timeParseErr *time.ParseError

		switch {
		case errors.As(err, &timeParseErr):
			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "expiredAt must be ISO 8601 format")
		default:
			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "Body must be valid JSON")
		}
		return
	}

	result, err := generateApiKey.usecase.Execute(r.Context(), parsedUserID, bodyParams.ExpiredAt)

	if err != nil {
		switch {
		case errors.Is(err, ErrApiKeyCountExceedsLimit):
			response.WriteErrorResponse(w, http.StatusConflict, "APIKEY_QUOTA_EXCEEDS_LIMIT", "Api key quota exceeds limit. Api key quota limit is "+strconv.Itoa(apiKeyMaxCount))
		case errors.Is(err, txrunner.ErrLockTimeout):
			response.WriteErrorResponse(w, http.StatusServiceUnavailable, "APIKEY_LOCK_TIMEOUT", "Api key generation is temporarily unavailable. Please try again later.")
		default:
			fmt.Printf("err %v", err)
			response.WriteInternalServerErrorResponse(w)
		}

		return
	}

	json.NewEncoder(w).Encode(result)
}

