	return User{
		userID:    dto.UserID,
		nickname:  dto.Nickname,
		introduce: dto.Introduce,
	}
}

func (u *User) UpdateProfile(nickname, introduce string) error {
	nicknameRunes := []rune(nickname)
	if len(nicknameRunes) < 1 || len(nicknameRunes) > 50 {
		return errors.New("nickname must be between 1 and 50 characters")
	}

	introduceRunes := []rune(introduce)
	if len(introduceRunes) > 500 {
		return errors.New("introduce must be 500 characters or less")
	}

	u.nickname = nickname
	u.introduce = introduce
	return nil
}

func (u User) Nickname() string {
	return u.nickname
}

func (u User) Introduce() string {
	return u.introduce
}

func (u User) UserID() uuid.UUID {
	return u.userID
}

